const St=({v,s=14})=><span style={{display:"inline-flex",alignItems:"center",gap:1}}>{[1,2,3,4,5].map(i=><span key={i} style={{fontSize:s,color:v>=i?"#F59E0B":v>=i-.5?"#FCD34D":"#D1D5DB"}}>★</span>)}<span style={{fontSize:Math.max(s*.8,11),fontWeight:700,color:P.mut,marginLeft:3}}>{v.toFixed(1)}</span></span>;
